const APPS_SCRIPT_URL="GANTI_URL_APPS_SCRIPT";async function checkAccess(e){if(!e)return!1;try{const t=new URLSearchParams({email:e.toLowerCase().trim(),ua:navigator.userAgent.slice(0,100),ref:location.hostname}),a=await fetch(APPS_SCRIPT_URL+"?"+t,{cache:"no-store"});if(!a.ok)return!1;return!0===(await a.json()).allowed}catch(e){return!1}}